// // This module multiplies the 2 most significant bits of the input by 3 and updates the output on the falling edge of the clock.
module Multiplier
  (
   input             clk,
   input [3:0]       in,
   output reg [1:0]  out
   );

   always @(posedge clk) begin
      out <= in[1:0] * 3;
   end

endmodule
